import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { Info } from '@mui/icons-material';
import response from './response.json';

interface MotionAlert {
  time: string;
  camera: string;
  alert: string;
}

interface SecurityData {
  activeCameras: number;
  recentMotionAlerts: MotionAlert[];
  status: string;
}

export default function Widget() {
  const securityData = response.data as SecurityData;
  const { activeCameras, recentMotionAlerts, status } = securityData;
  const meta = response.meta;

  return (
    <Card
      sx={{
        width: 'fit-content',
        minWidth: 320,
        maxWidth: 450,
        bgcolor: meta.theme === 'dark' ? '#1E1E1E' : '#FFFFFF',
        color: meta.theme === 'dark' ? '#FFFFFF' : '#000000',
      }}
      elevation={2}
    >
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: meta.primaryColor }}>
              Home Security
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Active Cameras: {activeCameras}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Status: {status}
            </Typography>
          </Box>

          <Stack spacing={1}>
            <Typography variant="body2" fontWeight={500} sx={{ mt: 1, color: meta.accentColor }}>
              Recent Motion Alerts
            </Typography>
            {recentMotionAlerts.map((alert, index) => (
              <Stack direction="row" alignItems="center" spacing={1} key={index}>
                <Info sx={{ fontSize: 16, color: meta.accentColor }} />
                <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
                  {alert.time} - {alert.camera}: {alert.alert}
                </Typography>
              </Stack>
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
